+// ──────────────────── manager ────────────────────
+
+/// Manages the lifecycle of ballast files: creation, verification, release, replenishment.
+pub struct BallastManager {
+    ballast_dir: PathBuf,
+    config: BallastConfig,
+    inventory: Vec<BallastFile>,
