+                    .ok()
+                    .and_then(|m| m.created().ok())
+                    .map(|t| {
+                        let dt: chrono::DateTime<chrono::Utc> = t.into();
+                        dt.to_rfc3339_opts(chrono::SecondsFormat::Millis, true)
+                    })
+                    .unwrap_or_default();
+
+                self.inventory.push(BallastFile {
+                    path: path.clone(),
+                    index,
+                    size,
+                    created_at,
+                    integrity_ok,
+                    released: false,
