+        let abi = if cfg!(target_env = "gnu") {
+            HostAbi::Gnu
+        } else if cfg!(target_env = "musl") {
+            HostAbi::Musl
+        } else if cfg!(target_env = "msvc") {
+            HostAbi::Msvc
