+    ///
+    /// On Unix: SIGTERM/SIGINT -> shutdown, SIGHUP -> reload, SIGUSR1 -> scan.
+    /// Registration is best-effort; failures are logged to stderr but not fatal.
+    pub fn new() -> Self {
+        let handler = Self {
