+#[cfg(target_os = "linux")]
+fn sd_notify_linux(status: &str) {
+    use std::os::unix::net::UnixDatagram;
+
+    let socket_path = match std::env::var("NOTIFY_SOCKET") {
+        Ok(p) if !p.is_empty() => p,
+        _ => return,
+    };
