+    let msg = format!("WATCHDOG=1\nSTATUS={status}\n");
+    let sock = match UnixDatagram::unbound() {
+        Ok(s) => s,
+        Err(_) => return,
+    };
+
+    let _ = sock.send_to(msg.as_bytes(), &socket_path);
