+                    self.maybe_fsync();
+                } else {
+                    self.degrade();
+                    self.write_line(line);
+                }
+            }
+            WriterState::Stderr => {
+                let _ = write!(io::stderr(), "[SBH-JSONL] {line}");
+            }
+            WriterState::Discard => {
