+    fn maybe_fsync(&mut self) {
+        let elapsed = SystemTime::now()
+            .duration_since(self.last_fsync)
+            .unwrap_or(Duration::ZERO);
+        if elapsed.as_secs() >= self.config.fsync_interval_secs {
+            self.fsync();
+        }
+    }
