+    fn degrade(&mut self) {
+        self.writer = None;
+        match self.state {
+            WriterState::Normal => {
+                self.try_open_fallback();
+            }
+            WriterState::Fallback => {
+                self.state = WriterState::Stderr;
+                let _ =
+                    writeln!(io::stderr(), "[SBH-JSONL] fallback write failed, using stderr");
+            }
+            WriterState::Stderr => {
+                self.state = WriterState::Discard;
