+    fn rotate(&mut self) {
+        // Flush and drop current file.
+        if let Some(w) = self.writer.as_mut() {
+            let _ = w.flush();
+        }
+        self.writer = None;
+
+        let base = match self.state {
+            WriterState::Normal => &self.config.path,
+            WriterState::Fallback => match &self.config.fallback_path {
+                Some(p) => p,
+                None => return,
+            },
+            _ => return,
+        };
