+        // Rename current → .1
+        let _ = rename(base, &rotated_name(base, 1));
+
+        // Reopen a fresh file.
+        match open_append(base) {
+            Ok((file, _)) => {
+                self.writer = Some(BufWriter::with_capacity(64 * 1024, file));
+                self.bytes_written = 0;
+            }
+            Err(_) => {
+                self.degrade();
+            }
+        }
+    }
