+        let est = make_estimate(500_000_000.0, 60.0, 0.95, Trend::Accelerating, false);
+        assert_eq!(
+            policy.evaluate(&est, 80.0, PathBuf::from("/data")),
+            PredictiveAction::Clear
+        );
+    }
